    def add(self, tokens):
        if len(tokens) == 2: # +a
            return tokens[1]
        if len(tokens) == 3: # a + b
            lh = tokens[0]
            rh = tokens[2]

            if self._obj_is_sympy_Matrix(lh) or self._obj_is_sympy_Matrix(rh):
                return sympy.MatAdd(lh, rh)

            return sympy.Add(lh, rh)

