    def determinant(self, tokens):
        if len(tokens) == 2: # \det A
            if not self._obj_is_sympy_Matrix(tokens[1]):
                raise LaTeXParsingError("Cannot take determinant of non-matrix.")

            return tokens[1].det()

        if len(tokens) == 3: # | A |
            return self.matrix(tokens).det()

